#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    for(int i=0;i<T;++i){
        double x,y,z;
        scanf("%lf %lf %lf",&x,&y,&z);
        double avg=(x+y+z)/3.0;
        printf("%.1f\n",avg);
    }
    return 0;
}

